import { useState, useEffect, useRef } from "react";

// ─── DB: localStorage com fallback em memória ──────────────────────────────────
const DB_KEY = "grupoinstruida_v1";
let _mem = { patients: {}, list: [] };

const db = {
  async read() {
    try {
      const raw = localStorage.getItem(DB_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        _mem = parsed;
        return parsed;
      }
    } catch {}
    return _mem;
  },
  async write(data) {
    _mem = { ...data };
    try { localStorage.setItem(DB_KEY, JSON.stringify(data)); }
    catch {}
  },
  async getPatient(code) {
    const d = await this.read();
    return d.patients?.[code] || null;
  },
  async savePatient(code, patientData) {
    const d = await this.read();
    if (!d.patients) d.patients = {};
    if (!d.list) d.list = [];
    d.patients[code] = patientData;
    const idx = d.list.findIndex(p => p.code === code);
    if (idx === -1) d.list.push({ code, name: patientData.name });
    else d.list[idx] = { code, name: patientData.name };
    await this.write(d);
  },
  async getList() {
    const d = await this.read();
    return d.list || [];
  },
  async getPlantoes() {
    const d = await this.read();
    return d.plantoes || [];
  },
  async savePlantoes(plantoes) {
    const d = await this.read();
    d.plantoes = plantoes;
    await this.write(d);
  },
  async reservarPlantao(id, pacienteCode, pacienteName) {
    const d = await this.read();
    d.plantoes = (d.plantoes || []).map(p =>
      p.id === id && p.status === "disponivel"
        ? { ...p, status: "aguardando", pacienteCode, pacienteName }
        : p
    );
    await this.write(d);
    return d.plantoes;
  },
  async confirmarPlantao(id) {
    const d = await this.read();
    const plantao = (d.plantoes || []).find(p => p.id === id);
    if (!plantao) return;
    // move to patient consultas
    if (plantao.pacienteCode && d.patients[plantao.pacienteCode]) {
      const pat = d.patients[plantao.pacienteCode];
      const consulta = { id: Date.now(), titulo: "⚡ Plantão", dataHora: plantao.dataHora, duracao: plantao.duracao, meet: plantao.meetLink || "", obs: "" };
      d.patients[plantao.pacienteCode] = { ...pat, consultas: [...(pat.consultas || []), consulta] };
    }
    d.plantoes = (d.plantoes || []).filter(p => p.id !== id);
    await this.write(d);
  },
  async cancelarPlantao(id) {
    const d = await this.read();
    d.plantoes = (d.plantoes || []).map(p =>
      p.id === id ? { ...p, status: "disponivel", pacienteCode: null, pacienteName: null } : p
    );
    await this.write(d);
  },
};

