const MoodSparkline = ({ entries }) => {
  if (!entries || entries.length < 2) return <p style={{ color: P.muted, fontSize: 12, margin: 0 }}>Registre seu humor por alguns dias para ver o gráfico 📈</p>;
  const last = entries.slice(-10);
  const W = 260, H = 60, pad = 8;
  const pts = last.map((e, i) => `${pad + (i / (last.length - 1)) * (W - pad * 2)},${H - pad - ((e.mood - 1) / 8) * (H - pad * 2)}`);
  return (
    <svg width={W} height={H} style={{ display: "block" }}>
      <defs><linearGradient id="mg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={P.sage} stopOpacity="0.3" /><stop offset="100%" stopColor={P.sage} stopOpacity="0" /></linearGradient></defs>
      <path d={`M${pts[0]} L${pts.join(" L")} L${W - pad},${H} L${pad},${H} Z`} fill="url(#mg)" />
      <polyline points={pts.join(" ")} fill="none" stroke={P.sage} strokeWidth="2.5" strokeLinejoin="round" />
      {last.map((e, i) => {
        const x = pad + (i / (last.length - 1)) * (W - pad * 2);
        const y = H - pad - ((e.mood - 1) / 8) * (H - pad * 2);
        return <circle key={i} cx={x} cy={y} r={3.5} fill={e.mood <= 2 ? P.alert : P.sage} />;
      })}
    </svg>
  );
};

const BreatheExercise = () => {
  const [active, setActive] = useState(false);
  const [step, setStep] = useState(0);
  const [count, setCount] = useState(0);
  const [cycle, setCycle] = useState(0);
  const ref = useRef();
  useEffect(() => {
    if (!active) return;
    ref.current = setInterval(() => {
      setCount(c => {
        if (c + 1 >= BREATHE_TIMES[step]) {
          setStep(s => { const n = (s + 1) % 4; if (n === 0) setCycle(cy => cy + 1); return n; });
          return 0;
        }
        return c + 1;
      });
    }, 1000);
    return () => clearInterval(ref.current);
  }, [active, step]);
  const stop = () => { setActive(false); setStep(0); setCount(0); setCycle(0); };
  const r = 54, circ = 2 * Math.PI * r;
  return (
    <div style={{ textAlign: "center" }}>
      <svg width={140} height={140} style={{ display: "block", margin: "0 auto 16px" }}>
        <circle cx={70} cy={70} r={r} fill="none" stroke={P.border} strokeWidth={6} />
        <circle cx={70} cy={70} r={r} fill="none" stroke={P.sage} strokeWidth={6} strokeDasharray={circ}
          strokeDashoffset={circ * (1 - (active ? (count + 1) / BREATHE_TIMES[step] : 0))}
          strokeLinecap="round" transform="rotate(-90 70 70)" style={{ transition: "stroke-dashoffset 0.9s linear" }} />
        <text x={70} y={66} textAnchor="middle" fontSize={14} fill={P.ink} fontWeight={700}>{active ? BREATHE_STEPS[step] : "Pronto?"}</text>
        <text x={70} y={84} textAnchor="middle" fontSize={20} fill={P.sage} fontWeight={700}>{active ? BREATHE_TIMES[step] - count : ""}</text>
      </svg>
      {active && <p style={{ color: P.muted, fontSize: 12, margin: "0 0 12px" }}>Ciclo {cycle + 1} · técnica 4-4-6-2</p>}
      {!active ? <Btn onClick={() => setActive(true)}>Iniciar respiração guiada</Btn> : <Btn onClick={stop} variant="ghost">Parar</Btn>}
    </div>
  );
};

const DrugChecker = ({ meds, setMeds }) => {
  const [psico, setPsico] = useState("");
  const [outro, setOutro] = useState("");
  const [inputPsico, setInputPsico] = useState("");
  const [inputOutro, setInputOutro] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [errPsico, setErrPsico] = useState("");
  const [errOutro, setErrOutro] = useState("");
  const sevColor = { grave: P.alert, moderada: P.clay, leve: P.sage, nenhuma: P.muted };

  const canAnalyze = psico && outro;

  const addPsico = (val) => {
    const v = val.trim();
    if (!v) return;
    const normalizado = v.toLowerCase();
    const bloqueado = OUTROS_MEDS.find(m => m.toLowerCase() === normalizado);
    if (bloqueado) { setErrPsico(`"${v}" está na lista B (outros medicamentos). Use-o lá.`); return; }
    setErrPsico(""); setPsico(v); setInputPsico("");
  };

  const addOutro = (val) => {
    const v = val.trim();
    if (!v) return;
    const normalizado = v.toLowerCase();
    const bloqueado = PSICOTROPICOS.find(m => m.toLowerCase() === normalizado);
    if (bloqueado) { setErrOutro(`"${v}" é um psicotrópico. Selecione-o na lista A.`); return; }
    setErrOutro(""); setOutro(v); setInputOutro("");
  };

  const analyze = async () => {
    if (!canAnalyze) return;
    setLoading(true); setResult(null);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, messages: [{ role: "user", content: `Você é um assistente farmacológico. Analise a interação entre o psicotrópico "${psico}" e o medicamento "${outro}". Responda SOMENTE JSON sem markdown:
{"interacoes":[{"par":"${psico} x ${outro}","severidade":"grave|moderada|leve|nenhuma","resumo":"explicação clara em 2-3 frases sobre a interação e o que monitorar"}]}` }] }) });
      const d = await res.json();
      setResult(JSON.parse(d.content?.map(b => b.text || "").join("").replace(/```json|```/g, "").trim()));
    } catch { setResult({ error: true }); }
    setLoading(false);
  };

  const inputStyle = { width: "100%", border: `1px solid ${P.border}`, borderRadius: 8, padding: "8px 12px", fontSize: 13, background: P.warm, outline: "none", color: P.ink, boxSizing: "border-box" };
  const chipStyle = (selected) => ({ padding: "4px 11px", borderRadius: 20, border: `1.5px solid ${selected ? P.lavender : P.border}`, background: selected ? P.lavender + "22" : P.warm, color: selected ? P.lavender : P.muted, fontSize: 12, fontWeight: selected ? 700 : 400, cursor: "pointer" });
  const chipStyleB = (selected) => ({ padding: "4px 11px", borderRadius: 20, border: `1.5px solid ${selected ? P.clay : P.border}`, background: selected ? P.clay + "22" : P.warm, color: selected ? P.clay : P.muted, fontSize: 12, fontWeight: selected ? 700 : 400, cursor: "pointer" });

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
      <div style={{ background: P.lavender + "12", borderRadius: 10, padding: "10px 14px", fontSize: 12, color: P.lavender, fontWeight: 600 }}>
        💊 Selecione <strong>um psicotrópico</strong> e <strong>um outro medicamento</strong> para verificar a interação entre eles.
      </div>

      {/* Coluna A: Psicotrópico */}
      <div>
        <div style={{ fontSize: 13, fontWeight: 700, color: P.ink, marginBottom: 8 }}>
          <span style={{ background: P.lavender + "22", color: P.lavender, borderRadius: 6, padding: "2px 8px", marginRight: 6, fontSize: 11 }}>A</span>
          Psicotrópico {psico && <span style={{ color: P.lavender, fontWeight: 700 }}>· {psico}</span>}
        </div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
          {PSICOTROPICOS.map(m => (
            <button key={m} onClick={() => setPsico(psico === m ? "" : m)} style={chipStyle(psico === m)}>{m}</button>
          ))}
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          <input value={inputPsico} onChange={e => setInputPsico(e.target.value)} onKeyDown={e => { if (e.key === "Enter") addPsico(inputPsico); }} placeholder="Outro psicotrópico..." style={inputStyle} />
          {inputPsico && <Btn small onClick={() => addPsico(inputPsico)}>Ok</Btn>}
        </div>
        {errPsico && <p style={{ color: P.alert, fontSize: 12, margin: "6px 0 0" }}>⚠️ {errPsico}</p>}
      </div>

      {/* Coluna B: Outro medicamento */}
      <div>
        <div style={{ fontSize: 13, fontWeight: 700, color: P.ink, marginBottom: 8 }}>
          <span style={{ background: P.clay + "22", color: P.clay, borderRadius: 6, padding: "2px 8px", marginRight: 6, fontSize: 11 }}>B</span>
          Outro medicamento {outro && <span style={{ color: P.clay, fontWeight: 700 }}>· {outro}</span>}
        </div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
          {OUTROS_MEDS.map(m => (
            <button key={m} onClick={() => setOutro(outro === m ? "" : m)} style={chipStyleB(outro === m)}>{m}</button>
          ))}
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          <input value={inputOutro} onChange={e => setInputOutro(e.target.value)} onKeyDown={e => { if (e.key === "Enter") addOutro(inputOutro); }} placeholder="Outro medicamento..." style={inputStyle} />
          {inputOutro && <Btn small onClick={() => addOutro(inputOutro)}>Ok</Btn>}
        </div>
        {errOutro && <p style={{ color: P.alert, fontSize: 12, margin: "6px 0 0" }}>⚠️ {errOutro}</p>}
      </div>

      {/* Botão */}
      <Btn onClick={analyze} disabled={!canAnalyze || loading} style={{ width: "100%" }}>
        {loading ? "Analisando..." : canAnalyze ? `Verificar: ${psico} × ${outro}` : "Selecione A e B para verificar"}
      </Btn>

      {/* Resultado */}
      {result && !result.error && (
        <div style={{ marginTop: 4 }}>
          {result.interacoes?.map((it, i) => (
            <div key={i} style={{ borderLeft: `4px solid ${sevColor[it.severidade] || P.muted}`, paddingLeft: 14, marginBottom: 10, background: (sevColor[it.severidade] || P.muted) + "08", borderRadius: "0 8px 8px 0", padding: "12px 14px" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
                <span style={{ fontSize: 13, fontWeight: 700, color: P.ink }}>{it.par}</span>
                <Badge color={sevColor[it.severidade] || P.muted}>{it.severidade}</Badge>
              </div>
              <p style={{ margin: 0, fontSize: 13, color: P.ink, lineHeight: 1.7 }}>{it.resumo}</p>
            </div>
          ))}
        </div>
      )}
      {result?.error && <p style={{ color: P.alert, fontSize: 13 }}>Erro ao consultar. Tente novamente.</p>}
    </div>
  );
};

const SupportChat = ({ name }) => {
  const [msgs, setMsgs] = useState([{ role: "assistant", text: `Olá${name ? ", " + name : ""}! 💚 Estou aqui para te ouvir. Como você está se sentindo agora?` }]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const endRef = useRef();
  useEffect(() => { endRef.current?.scrollIntoView({ behavior: "smooth" }); }, [msgs]);
  const send = async () => {
    if (!input.trim() || loading) return;
    const newMsgs = [...msgs, { role: "user", text: input }];
    setMsgs(newMsgs); setInput(""); setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, system: `Você é um assistente de apoio emocional gentil e empático. Ouça, acolha e ofereça suporte, mas NÃO faça diagnósticos. Seja caloroso, breve (max 3 frases). Paciente: ${name || "usuário"}.`, messages: newMsgs.map(m => ({ role: m.role, content: m.text })) }) });
      const d = await res.json();
      setMsgs(p => [...p, { role: "assistant", text: d.content?.map(b => b.text || "").join("") || "Estou aqui. Me conta mais." }]);
    } catch { setMsgs(p => [...p, { role: "assistant", text: "Desculpe, tive um problema. Mas estou aqui! 💚" }]); }
    setLoading(false);
  };
  return (
    <div style={{ display: "flex", flexDirection: "column", height: 360 }}>
      <div style={{ flex: 1, overflowY: "auto", display: "flex", flexDirection: "column", gap: 10, marginBottom: 12 }}>
        {msgs.map((m, i) => (
          <div key={i} style={{ display: "flex", justifyContent: m.role === "user" ? "flex-end" : "flex-start" }}>
            <div style={{ maxWidth: "80%", padding: "10px 14px", borderRadius: m.role === "user" ? "16px 16px 4px 16px" : "16px 16px 16px 4px", background: m.role === "user" ? P.sage : P.warm, color: m.role === "user" ? "#fff" : P.ink, fontSize: 13, lineHeight: 1.6 }}>{m.text}</div>
          </div>
        ))}
        {loading && <div style={{ display: "flex" }}><div style={{ background: P.warm, borderRadius: "16px 16px 16px 4px", padding: "10px 16px", color: P.muted, fontSize: 18, letterSpacing: 2 }}>···</div></div>}
        <div ref={endRef} />
      </div>
      <div style={{ display: "flex", gap: 8 }}>
        <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && send()} placeholder="Como você está se sentindo?" style={{ flex: 1, border: `1px solid ${P.border}`, borderRadius: 10, padding: "10px 14px", fontSize: 13, background: P.warm, outline: "none", color: P.ink }} />
        <Btn onClick={send} disabled={!input.trim() || loading}>→</Btn>
      </div>
    </div>
  );
};

