                <div><div style={{ fontSize: 13, fontWeight: 600, color: P.ink, textDecoration: t.done ? "line-through" : "none" }}>{t.text}</div>{t.note && <div style={{ fontSize: 12, color: P.muted, marginTop: 3 }}>💬 {t.note}</div>}</div>
