// codeInput LOCAL em cada view — re-renders isolados, sem derrubar o teclado
// ─── PSYCHO GLOBAL DASHBOARD ─────────────────────────────────────────────────
const PsychoDashboard = ({ onOpenPatient, onLogout }) => {
  const [patients, setPatients] = useState([]);
  const [allData, setAllData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState("overview"); // overview | list

  useEffect(() => {
    const load = async () => {
      const list = await db.getList();
      setPatients(list);
      const data = await Promise.all(list.map(p => db.getPatient(p.code)));
      setAllData(data.filter(Boolean));
      setLoading(false);
    };
    load();
  }, []);

  if (loading) return <Wrap><div style={{ color: P.muted }}>Carregando...</div></Wrap>;

  // ─── Stats ───
  const totalPacientes = patients.length;
  const comAnamnese = allData.filter(d => d.anamnese).length;
  const allMoods = allData.flatMap(d => (d.moodHistory || []).slice(-7));
  const avgMoodGeral = allMoods.length ? (allMoods.reduce((s, e) => s + e.mood, 0) / allMoods.length).toFixed(1) : "—";
  const now = new Date();
  const MOOD_LABELS = { 1: "Muito deprimido", 2: "Deprimido", 3: "Irritado", 4: "Ansioso", 5: "Cansado", 6: "Desanimado", 7: "Bem", 8: "Feliz", 9: "Com muita energia" };

  // Alerts across all patients
  const globalAlerts = [];
  allData.forEach(d => {
    const recent = (d.moodHistory || []).slice(-3);
    if (recent.length >= 3 && recent.every(e => e.mood <= 2))
      globalAlerts.push({ name: d.name, code: d.code, msg: "3 dias com humor muito baixo", type: "danger" });
    const recentImpulso = (d.moodHistory || []).slice(-5);
    const impulsoAlto = recentImpulso.filter(e => e.impulso === "Bastante" && e.impulsoImpacto === "alto");
    if (impulsoAlto.length > 0)
      globalAlerts.push({ name: d.name, code: d.code, msg: "Alta impulsividade registrada", type: "warn" });
  });

  // Mood distribution
  const moodCounts = {};
  allMoods.forEach(e => { moodCounts[e.mood] = (moodCounts[e.mood] || 0) + 1; });
  const moodDist = Object.entries(moodCounts).sort((a,b) => Number(a[0])-Number(b[0]));

  // Impulsivity stats
  const allImpulso = allData.flatMap(d => (d.moodHistory || []).filter(e => e.impulso && e.impulso !== "Não"));
  const impulsoRate = allMoods.length ? Math.round((allImpulso.length / allData.length) * 10) / 10 : 0;

  // Sleep stats
  const allSono = allData.flatMap(d => (d.moodHistory || []).filter(e => e.sono)).map(e => e.sono);
  const sonoRuim = allSono.filter(s => s.includes("Mal") || s.includes("Não dormi")).length;
  const sonoRuimPct = allSono.length ? Math.round((sonoRuim / allSono.length) * 100) : 0;

  // Recent activity (who registered today)
  const todayKey = now.toISOString().split("T")[0];
  const ativosHoje = allData.filter(d => (d.moodHistory || []).some(e => e.date === todayKey));

  const statCard = (val, label, color, sub) => (
    <Card style={{ textAlign: "center", padding: "14px 8px" }}>
      <div style={{ fontSize: 24, fontWeight: 800, color, fontFamily: "'DM Mono',monospace" }}>{val}</div>
      {sub && <div style={{ fontSize: 10, color: P.muted }}>{sub}</div>}
      <div style={{ fontSize: 11, fontWeight: 700, color: P.ink, marginTop: 3 }}>{label}</div>
    </Card>
  );

  return (
    <div style={{ minHeight: "100vh", background: P.bg, display: "flex", flexDirection: "column" }}>
      {/* Header */}
      <div style={{ background: P.ink, padding: "14px 20px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <div>
          <div style={{ fontSize: 17, fontWeight: 700, color: "#fff" }}>Grupo Instruída</div>
          <div style={{ fontSize: 12, color: P.muted }}>Painel geral da psicóloga</div>
        </div>
        <button onClick={onLogout} style={{ background: "none", border: "1px solid #ffffff30", borderRadius: 8, padding: "5px 12px", color: P.muted, fontSize: 12, cursor: "pointer" }}>⇄ Sair</button>
      </div>

      {/* Tabs */}
      <div style={{ background: P.ink, display: "flex", borderTop: "1px solid #ffffff15" }}>
        {[["overview", "📊 Visão Geral"], ["list", "👥 Pacientes"], ["fichas", "📋 Fichas"]].map(([id, label]) => (
          <button key={id} onClick={() => setView(id)} style={{ flex: 1, background: "none", border: "none", color: view === id ? P.blush : P.muted, fontWeight: view === id ? 700 : 400, padding: "10px", fontSize: 13, cursor: "pointer", borderBottom: `2px solid ${view === id ? P.blush : "transparent"}` }}>{label}</button>
        ))}
      </div>

      <div style={{ flex: 1, overflowY: "auto", padding: "18px 16px" }}>

        {/* ─── OVERVIEW ─── */}
        {view === "overview" && (
          <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>

            {/* Global alerts */}
            {globalAlerts.length > 0 && (
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: P.muted, textTransform: "uppercase", letterSpacing: 1 }}>🚨 Alertas</div>
                {globalAlerts.map((a, i) => (
                  <div key={i} onClick={() => onOpenPatient(a.code)} style={{ background: a.type === "danger" ? "#fdf1ee" : "#fff8ee", border: `1px solid ${a.type === "danger" ? P.alert : P.clay}40`, borderRadius: 10, padding: "10px 14px", display: "flex", gap: 10, alignItems: "center", cursor: "pointer" }}>
                    <span>{a.type === "danger" ? "🚨" : "⚠️"}</span>
                    <div style={{ flex: 1 }}>
                      <span style={{ fontWeight: 700, color: P.ink, fontSize: 13 }}>{a.name}</span>
                      <span style={{ fontSize: 12, color: a.type === "danger" ? P.alert : P.clay }}> · {a.msg}</span>
                    </div>
                    <span style={{ color: P.muted }}>→</span>
                  </div>
                ))}
              </div>
            )}

            {/* Stats grid */}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
              {statCard(totalPacientes, "Pacientes", P.sage, "")}
              {statCard(ativosHoje.length, "Ativos hoje", P.lavender, "registros")}
              {statCard(comAnamnese, "Com ficha", P.clay, "preenchida")}
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
              {statCard(avgMoodGeral, "Humor médio", P.sage, "últimos 7 dias")}
              {statCard(`${sonoRuimPct}%`, "Sono ruim", P.alert, "dos registros")}
              {statCard(impulsoRate, "Impuls./pac.", P.clay, "média episódios")}
            </div>

            {/* Mood distribution bar chart */}
            {moodDist.length > 0 && (
              <Card>
                <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 12 }}>Distribuição de humor (todos os pacientes)</div>
                {moodDist.map(([val, count]) => {
                  const pct = Math.round((count / allMoods.length) * 100);
                  const mood = Number(val);
                  const color = mood <= 2 ? P.alert : mood <= 4 ? P.clay : mood <= 6 ? P.muted : P.sage;
                  return (
                    <div key={val} style={{ marginBottom: 6 }}>
                      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: P.muted, marginBottom: 2 }}>
                        <span>{MOODS.find(m => m.val === mood)?.emoji} {MOOD_LABELS[mood]}</span>
                        <span style={{ fontWeight: 700 }}>{pct}% ({count})</span>
                      </div>
                      <div style={{ background: P.border, borderRadius: 4, height: 6 }}>
                        <div style={{ background: color, borderRadius: 4, height: 6, width: `${pct}%`, transition: "width 0.5s" }} />
                      </div>
                    </div>
                  );
                })}
              </Card>
            )}

            {/* Active today */}
            {ativosHoje.length > 0 && (
              <Card>
                <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>Registraram humor hoje</div>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                  {ativosHoje.map(d => {
                    const todayMoods = (d.moodHistory || []).filter(e => e.date === todayKey);
                    const lastMood = todayMoods[todayMoods.length - 1];
                    return (
                      <div key={d.code} onClick={() => onOpenPatient(d.code)} style={{ background: P.warm, border: `1px solid ${P.border}`, borderRadius: 20, padding: "4px 12px", cursor: "pointer", display: "flex", alignItems: "center", gap: 6 }}>
                        <span>{MOODS.find(m => m.val === lastMood?.mood)?.emoji}</span>
                        <span style={{ fontSize: 12, fontWeight: 600, color: P.ink }}>{d.name}</span>
                      </div>
                    );
                  })}
                </div>
              </Card>
            )}

            {totalPacientes === 0 && (
              <Card><p style={{ color: P.muted, fontSize: 13, margin: 0, textAlign: "center" }}>Nenhum paciente ainda. Vá em 👥 Pacientes para adicionar.</p></Card>
            )}
          </div>
        )}


        {/* ─── FICHAS / ESTATÍSTICAS ─── */}
        {view === "fichas" && (() => {
          const comFicha = allData.filter(d => d.anamnese);
          const total = comFicha.length;

          if (total === 0) return (
            <Card><p style={{ color: P.muted, fontSize: 13, margin: 0, textAlign: "center" }}>Nenhuma ficha preenchida ainda.</p></Card>
          );

          // Helpers
          const countBy = (key) => {
            const map = {};
            comFicha.forEach(d => { const v = d.anamnese[key]; if (v) map[v] = (map[v] || 0) + 1; });
            return Object.entries(map).sort((a,b) => b[1]-a[1]);
          };

          const calcIdade = (dataNasc) => {
            if (!dataNasc) return null;
            const diff = new Date() - new Date(dataNasc + "T12:00:00");
            return Math.floor(diff / (365.25 * 24 * 60 * 60 * 1000));
          };
          const idades = comFicha.map(d => calcIdade(d.anamnese.dataNascimento)).filter(Boolean);
          const avgIdade = idades.length ? Math.round(idades.reduce((a,b) => a+b, 0) / idades.length) : null;
          const idadeFaixas = { "< 18": 0, "18–25": 0, "26–35": 0, "36–45": 0, "46–60": 0, "60+": 0 };
          idades.forEach(i => {
            if (i < 18) idadeFaixas["< 18"]++;
            else if (i <= 25) idadeFaixas["18–25"]++;
            else if (i <= 35) idadeFaixas["26–35"]++;
            else if (i <= 45) idadeFaixas["36–45"]++;
            else if (i <= 60) idadeFaixas["46–60"]++;
            else idadeFaixas["60+"]++;
          });

          const generos = countBy("genero");
          const estados = comFicha.map(d => d.anamnese.cidadeEstado?.split("-").pop()?.trim()).filter(Boolean);
          const estadoMap = {};
          estados.forEach(e => { estadoMap[e] = (estadoMap[e] || 0) + 1; });
          const estadosDist = Object.entries(estadoMap).sort((a,b) => b[1]-a[1]);

          const escolaridade = countBy("escolaridade");
          const estadoCivil = countBy("estadoCivil");
          const terapiaAntes = countBy("terapiaAntes");
          const psiquiatraAntes = countBy("psiquiatraAntes");
          const diagnosticos = comFicha.map(d => d.anamnese.diagnostico).filter(d => d && d.trim().length > 2);
          const orientacao = countBy("orientacaoSexual");
          const comDiagnostico = comFicha.filter(d => d.anamnese.diagnostico && d.anamnese.diagnostico.trim().length > 2).length;
          const comFamiliaTranstorno = comFicha.filter(d => d.anamnese.familiaTranstorno === "Sim").length;
          const emAcompPsiq = comFicha.filter(d => d.anamnese.psiquiatraAntes === "Estou em acompanhamento").length;

          const BarChart = ({ data, total: tot, color }) => (
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {data.map(([label, count]) => {
                const pct = Math.round((count / tot) * 100);
                return (
                  <div key={label}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: P.muted, marginBottom: 2 }}>
                      <span>{label}</span><span style={{ fontWeight: 700 }}>{count} ({pct}%)</span>
                    </div>
                    <div style={{ background: P.border, borderRadius: 4, height: 6 }}>
                      <div style={{ background: color, borderRadius: 4, height: 6, width: `${pct}%`, transition: "width 0.5s" }} />
                    </div>
                  </div>
                );
              })}
            </div>
          );

          return (
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
              <div style={{ fontSize: 13, color: P.muted }}>{total} ficha{total > 1 ? "s" : ""} preenchida{total > 1 ? "s" : ""} de {allData.length} pacientes</div>

              {/* Resumo rápido */}
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
                {[
                  [avgIdade ? `${avgIdade}a` : "—", "Idade média", P.sage],
                  [`${comDiagnostico}`, "Com diagnóstico", P.alert],
                  [`${emAcompPsiq}`, "Em acomp. psiq.", P.lavender],
                ].map(([val, label, color]) => (
                  <Card key={label} style={{ textAlign: "center", padding: "12px 6px" }}>
                    <div style={{ fontSize: 22, fontWeight: 800, color }}>{val}</div>
                    <div style={{ fontSize: 10, color: P.muted, marginTop: 3, lineHeight: 1.3 }}>{label}</div>
                  </Card>
                ))}
              </div>

              {/* Idade */}
              {idades.length > 0 && (
                <Card>
                  <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>🎂 Faixa etária</div>
                  <BarChart data={Object.entries(idadeFaixas).filter(([,v]) => v > 0)} total={idades.length} color={P.sage} />
                </Card>
              )}

              {/* Gênero */}
              {generos.length > 0 && (
                <Card>
                  <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>🚻 Gênero</div>
                  <BarChart data={generos} total={total} color={P.lavender} />
                </Card>
              )}

              {/* Orientação sexual */}
              {orientacao.length > 0 && (
                <Card>
                  <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>🏳️‍🌈 Orientação sexual</div>
                  <BarChart data={orientacao} total={total} color={P.blush} />
                </Card>
              )}

              {/* Estado */}
              {estadosDist.length > 0 && (
                <Card>
                  <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>📍 Estado</div>
                  <BarChart data={estadosDist} total={estados.length} color={P.clay} />
                </Card>
              )}

              {/* Escolaridade */}
              {escolaridade.length > 0 && (
                <Card>
                  <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>🎓 Escolaridade</div>
                  <BarChart data={escolaridade} total={total} color={P.sage} />
                </Card>
              )}

              {/* Estado civil */}
              {estadoCivil.length > 0 && (
                <Card>
                  <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>💍 Estado civil</div>
                  <BarChart data={estadoCivil} total={total} color={P.clay} />
                </Card>
              )}

              {/* Histórico clínico */}
              <Card>
                <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>🏥 Histórico clínico</div>
                <BarChart data={terapiaAntes} total={total} color={P.lavender} />
                <div style={{ fontWeight: 700, color: P.muted, fontSize: 11, textTransform: "uppercase", margin: "10px 0 6px" }}>Psiquiatra</div>
                <BarChart data={psiquiatraAntes} total={total} color={P.blush} />
                <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
                  <div style={{ flex: 1, background: P.alert + "12", borderRadius: 10, padding: "10px", textAlign: "center" }}>
                    <div style={{ fontSize: 20, fontWeight: 800, color: P.alert }}>{comDiagnostico}</div>
                    <div style={{ fontSize: 10, color: P.muted }}>com diagnóstico</div>
                  </div>
                  <div style={{ flex: 1, background: P.clay + "12", borderRadius: 10, padding: "10px", textAlign: "center" }}>
                    <div style={{ fontSize: 20, fontWeight: 800, color: P.clay }}>{comFamiliaTranstorno}</div>
                    <div style={{ fontSize: 10, color: P.muted }}>histórico familiar</div>
                  </div>
                </div>
              </Card>

              {/* Diagnósticos listados */}
              {diagnosticos.length > 0 && (
                <Card>
                  <div style={{ fontWeight: 700, color: P.ink, fontSize: 13, marginBottom: 10 }}>📝 Diagnósticos relatados</div>
                  {diagnosticos.map((d, i) => (
                    <div key={i} style={{ fontSize: 12, color: P.muted, padding: "5px 0", borderBottom: `1px solid ${P.border}` }}>• {d.slice(0, 120)}{d.length > 120 ? "..." : ""}</div>
                  ))}
                </Card>
              )}
            </div>
          );
        })()}

        {/* ─── PATIENT LIST ─── */}
        {view === "list" && (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            <AddPatientCard onAdded={() => { db.getList().then(setPatients); db.getList().then(l => Promise.all(l.map(p => db.getPatient(p.code)))).then(d => setAllData(d.filter(Boolean))); }} />
            {patients.length === 0
              ? <Card><p style={{ color: P.muted, fontSize: 13, margin: 0, textAlign: "center" }}>Nenhum paciente ainda.<br />Peça o código ao paciente.</p></Card>
              : patients.map(p => {
                const pd = allData.find(d => d.code === p.code || d.name === p.name);
                const lastMood = pd && (pd.moodHistory || []).slice(-1)[0];
                const hasFicha = pd?.anamnese;
                const hasAlert = globalAlerts.some(a => a.code === p.code);
                return (
                  <Card key={p.code} onClick={() => onOpenPatient(p.code)} style={{ cursor: "pointer", display: "flex", alignItems: "center", gap: 14 }}>
                    <div style={{ width: 42, height: 42, borderRadius: 21, background: P.sage + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>
                      {lastMood ? MOODS.find(m => m.val === lastMood.mood)?.emoji : "🧘"}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                        <span style={{ fontWeight: 700, color: P.ink, fontSize: 15 }}>{p.name}</span>
                        {hasAlert && <span style={{ fontSize: 14 }}>🚨</span>}
                      </div>
                      <div style={{ fontSize: 11, color: P.muted, letterSpacing: 1 }}>{p.code}</div>
                      <div style={{ display: "flex", gap: 4, marginTop: 3 }}>
                        {hasFicha && <Badge color={P.sage}>📋 ficha</Badge>}
                        {lastMood && <Badge color={P.lavender}>😊 {new Date(lastMood.date).toLocaleDateString("pt-BR", { day: "numeric", month: "short" })}</Badge>}
                      </div>
                    </div>
                    <span style={{ color: P.muted, fontSize: 18 }}>→</span>
                  </Card>
                );
              })
            }
          </div>
        )}
      </div>
    </div>
  );
};

const AddPatientCard = ({ onAdded }) => {
  const [codeInput, setCodeInput] = useState("");
  const [codeError, setCodeError] = useState("");
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);

  const addPatient = async () => {
    if (!codeInput.trim()) return;
    setLoading(true); setCodeError("");
    const c = codeInput.trim().toUpperCase().replace(/[^A-Z0-9]/g, "");
    const d = await db.getPatient(c);
    if (!d) { setCodeError(`Código "${c}" não encontrado.`); setLoading(false); return; }
    await db.savePatient(c, d);
    setCodeInput(""); setLoading(false); setOpen(false);
    onAdded();
  };

  return (
    <Card style={{ borderLeft: `4px solid ${P.sage}` }}>
      <button onClick={() => setOpen(o => !o)} style={{ background: "none", border: "none", width: "100%", display: "flex", alignItems: "center", gap: 10, cursor: "pointer", padding: 0 }}>
        <span style={{ fontSize: 20 }}>➕</span>
        <span style={{ fontWeight: 700, color: P.ink, fontSize: 13 }}>Adicionar paciente pelo código</span>
        <span style={{ marginLeft: "auto", color: P.muted }}>{open ? "▲" : "▼"}</span>
      </button>
      {open && (
        <div style={{ marginTop: 12 }}>
          <div style={{ display: "flex", gap: 8 }}>
            <input value={codeInput} onChange={e => { setCodeInput(e.target.value.toUpperCase()); setCodeError(""); }}
              onKeyDown={e => e.key === "Enter" && codeInput.length >= 3 && addPatient()}
              maxLength={5} placeholder="Código (ex: AB3XY)"
              style={{ flex: 1, border: `1px solid ${codeError ? P.alert : P.border}`, borderRadius: 8, padding: "9px 12px", fontSize: 16, fontWeight: 700, letterSpacing: 3, textAlign: "center", background: P.warm, outline: "none", color: P.ink }} />
            <Btn onClick={addPatient} disabled={codeInput.length < 3 || loading} small>{loading ? "..." : "Buscar"}</Btn>
          </div>
          {codeError && <p style={{ color: P.alert, fontSize: 12, margin: "6px 0 0" }}>{codeError}</p>}
        </div>
      )}
    </Card>
  );
};

const PsychoList = ({ onOpenPatient, onLogout }) => {
  const [codeInput, setCodeInput] = useState("");
  const [codeError, setCodeError] = useState("");
  const [loading, setLoading] = useState(false);
  const [patients, setPatients] = useState([]);

  useEffect(() => { db.getList().then(setPatients); }, []);

  const addPatient = async () => {
    if (!codeInput.trim()) return;
    setLoading(true); setCodeError("");
    const c = codeInput.trim().toUpperCase().replace(/[^A-Z0-9]/g, "");
    const d = await db.getPatient(c);
    if (!d) {
      setCodeError(`Código "${c}" não encontrado. O paciente precisa criar a conta primeiro.`);
      setLoading(false); return;
    }
    await db.savePatient(c, d);
    setPatients(await db.getList());
    setCodeInput(""); setLoading(false);
  };

  return (
    <Wrap>
      <div style={{ width: "100%", maxWidth: 400 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <div>
            <img src="data:image/png;base64," alt="Grupo Instruída" style={{ width: 180, display: "block", marginBottom: 4 }} />
            <div style={{ fontSize: 22, fontWeight: 700, color: P.ink }}>Meus pacientes</div>
            <div style={{ fontSize: 12, color: P.muted }}>Selecione para ver o painel clínico</div>
          </div>
          <button onClick={onLogout} style={{ background: "none", border: `1px solid ${P.border}`, borderRadius: 8, padding: "5px 12px", color: P.muted, fontSize: 12, cursor: "pointer" }}>⇄ Sair</button>
        </div>
        <Card style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: P.ink, marginBottom: 6 }}>Adicionar paciente pelo código</div>
          <div style={{ fontSize: 12, color: P.muted, marginBottom: 10 }}>O paciente cria a conta e compartilha o código de 5 caracteres com você.</div>
          <div style={{ display: "flex", gap: 8 }}>
            <input
              value={codeInput}
              onChange={e => { setCodeInput(e.target.value.toUpperCase()); setCodeError(""); }}
              onKeyDown={e => e.key === "Enter" && codeInput.length >= 3 && addPatient()}
              maxLength={5}
              placeholder="Ex: AB3XY"
              style={{ flex: 1, border: `1px solid ${codeError ? P.alert : P.border}`, borderRadius: 8, padding: "9px 12px", fontSize: 18, fontWeight: 700, letterSpacing: 4, textAlign: "center", background: P.warm, outline: "none", color: P.ink }}
            />
            <Btn onClick={addPatient} disabled={codeInput.length < 3 || loading} small>{loading ? "..." : "Buscar"}</Btn>
          </div>
          {codeError && <p style={{ color: P.alert, fontSize: 12, margin: "8px 0 0" }}>{codeError}</p>}
        </Card>
        {patients.length === 0
          ? <Card><p style={{ color: P.muted, fontSize: 13, margin: 0, textAlign: "center" }}>Nenhum paciente ainda.<br />Peça o código de 5 caracteres ao paciente.</p></Card>
          : patients.map(p => (
            <Card key={p.code} onClick={() => onOpenPatient(p.code)} style={{ cursor: "pointer", marginBottom: 10, display: "flex", alignItems: "center", gap: 14 }}>
              <div style={{ width: 40, height: 40, borderRadius: 20, background: P.sage + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18 }}>🧘</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, color: P.ink, fontSize: 15 }}>{p.name}</div>
                <div style={{ fontSize: 11, color: P.muted, letterSpacing: 2 }}>{p.code}</div>
              </div>
              <span style={{ color: P.muted, fontSize: 18 }}>→</span>
            </Card>
          ))
        }
      </div>
    </Wrap>
  );
};

const PatientReturn = ({ onLogin, onBack }) => {
  const [codeInput, setCodeInput] = useState("");
  const [codeError, setCodeError] = useState("");
  const [loading, setLoading] = useState(false);

  const loginPatient = async () => {
    if (!codeInput.trim()) return;
    setLoading(true); setCodeError("");
    const c = codeInput.trim().toUpperCase().replace(/[^A-Z0-9]/g, "");
    const d = await db.getPatient(c);
    if (!d) { setCodeError(`Código "${c}" não encontrado.`); setLoading(false); return; }
    onLogin(c, d);
  };

  return (
    <Wrap>
      <Card style={{ maxWidth: 340, width: "100%", textAlign: "center" }}>
        <img src="data:image/png;base64," alt="logo" style={{ width: 70, marginBottom: 10 }} />
        <div style={{ fontSize: 20, fontWeight: 700, color: P.ink, marginBottom: 4 }}>Entrar com código</div>
        <p style={{ color: P.muted, fontSize: 13, marginBottom: 18, lineHeight: 1.6 }}>Digite o código de 5 caracteres do seu perfil.</p>
        <input
          value={codeInput}
          onChange={e => { setCodeInput(e.target.value.toUpperCase()); setCodeError(""); }}
          onKeyDown={e => e.key === "Enter" && loginPatient()}
          maxLength={5}
          placeholder="AB3XY"
          style={{ width: "100%", border: `1px solid ${codeError ? P.alert : P.border}`, borderRadius: 10, padding: "11px 14px", fontSize: 26, fontWeight: 700, letterSpacing: 8, textAlign: "center", background: P.warm, outline: "none", color: P.ink, boxSizing: "border-box", marginBottom: codeError ? 8 : 14 }}
        />
        {codeError && <p style={{ color: P.alert, fontSize: 12, margin: "0 0 12px" }}>{codeError}</p>}
        <Btn onClick={loginPatient} disabled={codeInput.length < 3 || loading} style={{ width: "100%" }}>{loading ? "Buscando..." : "Entrar"}</Btn>
        <button onClick={onBack} style={{ background: "none", border: "none", color: P.muted, fontSize: 12, cursor: "pointer", marginTop: 12 }}>← Voltar</button>
      </Card>
    </Wrap>
  );
};

export default function GrupoInstruidaApp() {
  const [view, setView] = useState("login");
  const [appData, setAppData] = useState(null);
  const [appCode, setAppCode] = useState("");
  const [patientName, setPatientName] = useState("");
  const [loading, setLoading] = useState(false);

  const logout = () => { setView("login"); setAppData(null); setAppCode(""); setPatientName(""); };

  const createPatient = async () => {
    if (!patientName.trim()) return;
    setLoading(true);
    const c = genCode();
    const newData = { name: patientName.trim(), code: c, moodHistory: [], tasks: [], meds: [], createdAt: Date.now() };
    await db.savePatient(c, newData);
    setAppCode(c); setAppData(newData); setView("anamnese"); setLoading(false);
  };

  const openPatient = async (c) => {
    setLoading(true);
    const d = await db.getPatient(c);
    setAppCode(c); setAppData(d); setView("psychologist"); setLoading(false);
  };

  const savePatient = async (updated) => { setAppData(updated); await db.savePatient(appCode, updated); };

  if (view === "login") return (
    <Wrap>
      <div style={{ textAlign: "center", marginBottom: 36 }}>
        <img src="data:image/png;base64," alt="Grupo Instruída" style={{ width: 320, maxWidth: "90vw" }} />
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 12, width: "100%", maxWidth: 320 }}>
        <Card style={{ cursor: "pointer" }} onClick={() => setView("patient-new")}>
          <div style={{ display: "flex", alignItems: "center", gap: 14 }}><span style={{ fontSize: 28 }}>🧘</span><div><div style={{ fontWeight: 700, color: P.ink, fontSize: 15 }}>Sou paciente — primeiro acesso</div><div style={{ fontSize: 12, color: P.muted }}>Criar minha conta</div></div></div>
        </Card>
        <Card style={{ cursor: "pointer" }} onClick={() => setView("patient-return")}>
          <div style={{ display: "flex", alignItems: "center", gap: 14 }}><span style={{ fontSize: 28 }}>🔑</span><div><div style={{ fontWeight: 700, color: P.ink, fontSize: 15 }}>Já tenho meu código</div><div style={{ fontSize: 12, color: P.muted }}>Entrar com código de 5 caracteres</div></div></div>
        </Card>
        <Card style={{ cursor: "pointer" }} onClick={() => setView("psycho-list")}>
          <div style={{ display: "flex", alignItems: "center", gap: 14 }}><span style={{ fontSize: 28 }}>👩‍⚕️</span><div><div style={{ fontWeight: 700, color: P.ink, fontSize: 15 }}>Sou psicólogo(a)</div><div style={{ fontSize: 12, color: P.muted }}>Acessar painel clínico</div></div></div>
        </Card>
      </div>
      {loading && <div style={{ marginTop: 16, color: P.muted, fontSize: 13 }}>Carregando...</div>}
    </Wrap>
  );

  if (view === "patient-new") return (
    <Wrap>
      <Card style={{ maxWidth: 340, width: "100%", textAlign: "center" }}>
        <img src="data:image/png;base64," alt="logo" style={{ width: 70, marginBottom: 10 }} />
        <div style={{ fontSize: 20, fontWeight: 700, color: P.ink, marginBottom: 4 }}>Criar minha conta</div>
        <p style={{ color: P.muted, fontSize: 13, marginBottom: 18, lineHeight: 1.6 }}>Como posso te chamar?</p>
        <input value={patientName} onChange={e => setPatientName(e.target.value)} onKeyDown={e => e.key === "Enter" && createPatient()} placeholder="Seu nome" style={{ width: "100%", border: `1px solid ${P.border}`, borderRadius: 10, padding: "11px 14px", fontSize: 14, background: P.warm, outline: "none", color: P.ink, boxSizing: "border-box", marginBottom: 14 }} />
        <Btn onClick={createPatient} disabled={!patientName.trim() || loading} style={{ width: "100%" }}>{loading ? "Criando..." : "Criar conta"}</Btn>
        <button onClick={() => setView("login")} style={{ background: "none", border: "none", color: P.muted, fontSize: 12, cursor: "pointer", marginTop: 12 }}>← Voltar</button>
      </Card>
    </Wrap>
  );

  if (view === "patient-return") return <PatientReturn onLogin={(c, d) => { setAppCode(c); setAppData(d); setView("patient"); }} onBack={() => setView("login")} />;
  if (view === "anamnese") return <AnamneseForm data={appData} code={appCode} onSave={async (anamnese) => { const updated = { ...appData, anamnese }; setAppData(updated); await db.savePatient(appCode, updated); setView("patient"); }} onSkip={() => setView("patient")} />;
  if (view === "psycho-list") return <PsychoDashboard onOpenPatient={openPatient} onLogout={logout} />;
  if (!appData) return <div style={{ padding: 40, textAlign: "center", color: P.muted }}>Carregando...</div>;
  if (view === "patient") return <PatientView data={appData} code={appCode} onSave={savePatient} onLogout={logout} />;
  if (view === "psychologist") return <PsychologistView data={appData} code={appCode} onSave={savePatient} onBack={() => setView("psycho-list")} />;
}
